// =========================================================
// HELPERS
// =========================================================
const isEmpty = (v) => v === "" || v === undefined || v === null;
const norm = (v) => (isEmpty(v) ? null : v);

function get(obj, path, fallback = null) {
  try {
    const parts = path.split(".");
    let cur = obj;
    for (const p of parts) {
      if (cur == null) return fallback;
      cur = cur[p];
    }
    return cur === undefined ? fallback : cur;
  } catch {
    return fallback;
  }
}

function toISODateFromBR(dateStr) {
  if (!dateStr || typeof dateStr !== "string") return null;
  const m = dateStr.trim().match(/^(\d{2})\/(\d{2})\/(\d{2}|\d{4})$/);
  if (!m) return null;

  const dd = parseInt(m[1], 10);
  const mm = parseInt(m[2], 10);
  let yy = m[3];
  if (yy.length === 2) yy = "20" + yy;
  const yyyy = parseInt(yy, 10);

  if (!(yyyy >= 2000 && yyyy <= 2099)) return null;
  if (!(mm >= 1 && mm <= 12)) return null;
  if (!(dd >= 1 && dd <= 31)) return null;

  const d = new Date(Date.UTC(yyyy, mm - 1, dd));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== yyyy || d.getUTCMonth() !== (mm - 1) || d.getUTCDate() !== dd) return null;

  return `${String(yyyy).padStart(4, "0")}-${String(mm).padStart(2, "0")}-${String(dd).padStart(2, "0")}`;
}

function isoDateOnlyUTC(d) {
  if (!d || isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  const da = String(d.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${da}`;
}

function todayISODateUTC() {
  const now = new Date();
  return isoDateOnlyUTC(now);
}

function evalISODateUTC() {
  const ts = norm(get(input, "document_metadata.analysis_timestamp", null))
    ?? norm(get(input, "document_metadata.analysisTimestamp", null));

  if (ts && typeof ts === "string") {
    const d = new Date(ts);
    const iso = isoDateOnlyUTC(d);
    if (iso) return iso;
  }
  return todayISODateUTC();
}

function parseISODateToUTC(isoDate) {
  if (!isoDate || typeof isoDate !== "string") return null;
  const m = isoDate.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!m) return null;
  const y = parseInt(m[1], 10);
  const mo = parseInt(m[2], 10);
  const da = parseInt(m[3], 10);
  const d = new Date(Date.UTC(y, mo - 1, da));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== y || d.getUTCMonth() !== (mo - 1) || d.getUTCDate() !== da) return null;
  return d;
}

function daysBetweenUTC(a, b) {
  const ms = b.getTime() - a.getTime();
  return Math.floor(ms / 86400000);
}

function clampScore(n) {
  const x = Number.isFinite(n) ? n : 0;
  return Math.max(0, Math.min(100, x));
}

function anyTrue(obj) {
  if (!obj || typeof obj !== "object") return false;
  return Object.values(obj).some((v) => v === true);
}

function hasQuestionMarks(name) {
  if (!name || typeof name !== "string") return false;
  return name.includes("?") || name.includes("�");
}

function inSet(v, arr) {
  return arr.includes(v);
}

function piecewiseDocAgePenalty(ageDays) {
  if (!Number.isFinite(ageDays)) return 0;
  if (ageDays <= MAX_DOCUMENT_AGE_DAYS_FOR_AUTO) return 0;
  if (ageDays <= 60) return 6;
  if (ageDays <= 120) return 12;
  if (ageDays <= 365) return 22;
  return 30;
}

function piecewiseCompletenessPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.60) return 28;
  if (v < 0.75) return 18;
  if (v < 0.85) return 12;
  if (v < 0.90) return 6;
  return 0;
}

function piecewiseQualityPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.60) return 15;
  if (v < 0.85) return 6;
  return 0;
}

function piecewiseConsistencyPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.75) return 10;
  if (v < 0.90) return 4;
  return 0;
}

function addPenalty(arr, code, points, evidence, meta = {}) {
  if (!Number.isFinite(points) || points <= 0) return;
  arr.push({ code, points, evidence: evidence || "", ...meta });
}

function addBonus(arr, code, points, evidence, meta = {}) {
  if (!Number.isFinite(points) || points >= 0) return;
  arr.push({ code, points, evidence: evidence || "", ...meta });
}

// =========================================================
