// =========================================================
// DATE RULES
// =========================================================
const evalISO = evalISODateUTC();
const dAtt = attendanceDateISO ? parseISODateToUTC(attendanceDateISO) : null;
const dEval = parseISODateToUTC(evalISO);

const attendanceAgeDays = (() => {
  if (!dAtt || !dEval) return null;
  return daysBetweenUTC(dAtt, dEval); // eval - attendance
})();

const isFutureAttendance = (() => {
  if (!dAtt || !dEval) return false;
  return dAtt.getTime() > dEval.getTime();
})();

const withinMaxAutoDays = (() => {
  if (attendanceAgeDays === null) return false;
  return attendanceAgeDays >= 0 && attendanceAgeDays <= MAX_DOCUMENT_AGE_DAYS_FOR_AUTO;
})();

// =========================================================
// LEAVE vs ATTENDANCE TEMPORAL CONSISTENCY (HIGH RISK)
// =========================================================
const dLeaveStart = leaveStartISO ? parseISODateToUTC(leaveStartISO) : null;

const leavePresent = (() => {
  const d = leaveDays ?? 0;
  const h = leaveHours ?? 0;
  const hasStart = !!leaveStartISO;
  const hasEnd = !!leaveEndISO;
  const hasWindow = (!!leaveStartHour || !!leaveEndHour);
  const indef = String(periodoIndefinido || "").toUpperCase() === "S";

  return (
    !!leaveType ||
    (Number.isFinite(d) && d > 0) ||
    (Number.isFinite(h) && h > 0) ||
    hasStart ||
    hasEnd ||
    hasWindow ||
    indef
  );
})();

const leaveTemporalDiffDays = (() => {
  if (!dAtt || !dLeaveStart) return null;
  return daysBetweenUTC(dAtt, dLeaveStart);
})();

const leaveTemporalHighRisk = (() => {
  if (!leavePresent) return false;
  if (!dAtt || !dLeaveStart) return false;
  const diffDays = leaveTemporalDiffDays;
  if (!Number.isFinite(diffDays)) return false;
  return diffDays < 0 || diffDays > MAX_LEAVE_START_OFFSET_DAYS;
})();

const leaveDatesConsistent = (() => {
  if (!leavePresent) return true;

  const indef = String(periodoIndefinido || "").toUpperCase() === "S";
  const hasStart = !!leaveStartISO;
  const hasEnd = !!leaveEndISO;

  if (!hasStart) return false;
  if (!hasEnd && indef) return true;
  if (hasStart !== hasEnd) return false;

  const s = parseISODateToUTC(leaveStartISO);
  const e = parseISODateToUTC(leaveEndISO);
  if (!s || !e) return false;
  return e.getTime() >= s.getTime();
})();

const leaveRiskOkForAuto = inSet(leaveDaysRisk, ["very_low", "low"]);

// =========================================================
