// ---------------------- Helpers ----------------------

function normalizeName(name) {
  return (name || "")
    .toUpperCase()
    .replace(/\b(DR|DRA|DR\.)\b/g, "")
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z\s]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenize(name) {
  return normalizeName(name).split(" ").filter(Boolean);
}

// [MIN-CHANGE] small Levenshtein for surname-only penalty
function levenshtein(a, b) {
  a = a || ""; b = b || "";
  const n = a.length, m = b.length;
  if (n === 0) return m;
  if (m === 0) return n;

  const dp = new Array(m + 1);
  for (let j = 0; j <= m; j++) dp[j] = j;

  for (let i = 1; i <= n; i++) {
    let prev = dp[0];
    dp[0] = i;
    for (let j = 1; j <= m; j++) {
      const tmp = dp[j];
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[j] = Math.min(
        dp[j] + 1,        // deletion
        dp[j - 1] + 1,    // insertion
        prev + cost       // substitution
      );
      prev = tmp;
    }
  }
  return dp[m];
}

/**
 * Name similarity score ∈ [0,1]
 * Improvements:
 * - rewards whole-word overlap more strongly
 * - keeps strong surname match weight
 * - penalizes "almost surname" typos (e.g., MOLER vs MOLTER)
 */
function nameSimilarity(a, b) {
  const ta = tokenize(a);
  const tb = tokenize(b);

  if (!ta.length || !tb.length) return 0;

  const setA = new Set(ta);
  const setB = new Set(tb);

  const intersectionCount = [...setA].filter(t => setB.has(t)).length;

  // token F1 (whole-word overlap)
  const prec = intersectionCount / setA.size;
  const rec  = intersectionCount / setB.size;
  const f1 = (prec + rec) > 0 ? (2 * prec * rec) / (prec + rec) : 0; // 0..1

  const surnameA = ta[ta.length - 1];
  const surnameB = tb[tb.length - 1];
  const surnameExact = surnameA === surnameB;

  // Base score: whole-word overlap dominates
  // (makes BARBARA FREIRE vs BARBARA FREIRE DOS SANTOS go > 0.5)
  let score = 0.75 * f1;

  // Surname bonus (strong)
  if (surnameExact) {
    score += 0.25; // total can reach 1.0
  } else {
    // If surname is "almost" the same, we penalize (to avoid MOLER ~ MOLTER being too high)
    // normalized surname similarity ∈ [0,1]
    const dist = levenshtein(surnameA, surnameB);
    const maxLen = Math.max(surnameA.length, surnameB.length, 1);
    const surnameSim = 1 - (dist / maxLen);

    // If surname similarity is moderate-high but not exact, force it down
    // This pushes cases like MOLER vs MOLTER closer to ~0.25 rather than ~0.5+
    if (surnameSim >= 0.7) {
      score *= 0.55; // strong downscale for near-miss surname
    } else if (surnameSim >= 0.5) {
      score *= 0.75; // moderate downscale
    }
  }

  return Math.max(0, Math.min(score, 1));
}

