const qrInput   = $('Leitor de QR Code').first().json.stdout; // QR Reader
// ==========================================


// ---------------- Helpers ----------------
function parseJSONSafe(value) {
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    try { return JSON.parse(value); } catch { return null; }
  }
  return null;
}

// ---------------- Output ----------------
const result = {
  qr_exists: false,
  qr_decodable: false,
  qr_target_url: "",
  qr_domain: "",
  qr_bbox: {
    x: 0,
    y: 0,
    width: 0,
    height: 0
  },
  qr_url_status: "error"
};

// ---------------- HTTP (STRICT) ----------------
if (httpInput && httpInput.statusCode === 200) {
  result.qr_url_status = "active";
}

// ---------------- QR (STRICT) ----------------
const qr = parseJSONSafe(qrInput);

if (qr) {
  result.qr_exists = qr.qr_exists === true;
  result.qr_decodable = qr.qr_decodable === true;
  result.qr_target_url = qr.qr_text || "";
  result.qr_domain = qr.qr_domain || "";

  if (qr.qr_bbox) {
    result.qr_bbox = {
      x: qr.qr_bbox.x ?? 0,
      y: qr.qr_bbox.y ?? 0,
      width: qr.qr_bbox.width ?? 0,
      height: qr.qr_bbox.height ?? 0
    };
  }
}

// ---------------- Final rule ----------------
if (!(result.qr_exists && result.qr_decodable && httpInput?.statusCode === 200)) {
  result.qr_url_status = "error";
}

// ---------------- Return ----------------
return [{ json: result }];

