  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        statusMessage: response.statusMessage,
        error: "URL não acessível (status inválido)",
      },
    },
  ];
}

// ============================================
// Valida Content-Type
// ============================================

const contentType =
  response.headers?.["content-type"] ||
  response.headers?.["Content-Type"] ||
  null;

// Extensões permitidas
const allowedExtensions = ["webp", "jpg", "jpeg", "png", "gif", "bmp"];

// Extrai extensão da URL sem querystring
const urlExtension = (() => {
  try {
    const cleanUrl = urlImage.split("?")[0];
    return cleanUrl.split(".").pop().toLowerCase();
  } catch {
    return "";
  }
})();

// Regras:
// - Content-Type deve começar com image/
// OU extensão deve ser conhecida
