if (!isImageByContentType && !isImageByExtension) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        contentType,
        extension: urlExtension || null,
        error:
          "Arquivo acessível, mas não é uma imagem válida (Content-Type incorreto)",
      },
    },
  ];
}

// ============================================
