// ============================================

const now = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp =
  now.getFullYear() +
  pad(now.getMonth() + 1, 2) +
  pad(now.getDate(), 2) +
  pad(now.getHours(), 2) +
  pad(now.getMinutes(), 2) +
  pad(now.getSeconds(), 2) +
  pad(now.getMilliseconds(), 3);

const FILE_PREFIX = timestamp;

// ============================================
