        if (emp_name_score >= EMPLOYEE_NAME_MATCH_MIN_SCORE) return 0;
        if (emp_name_score >= 0.40) return 35;
        if (emp_name_score >= 0.25) return 45;
        return 55;
      },
      apply_if: () => employeeCrossCheckRequired === true,
      evidence: () => `employee_cross_check=true,name_score=${emp_name_score},min=${EMPLOYEE_NAME_MATCH_MIN_SCORE}`
    },
    {
      code: "P_EMPLOYEE_NAME_MATCH_FALSE",
      points: 55,
      apply_if: () => (employeeCrossCheckRequired === true && emp_name_match === false),
      evidence: () => `employee_cross_check=true,name_match=false,name_score=${emp_name_score}`
    },
    {
      code: "P_EMPLOYEE_ALL_DOCUMENTS_MISMATCH",
      points: 75,
      apply_if: () => (employeeCrossCheckRequired === true && emp_all_documents_match === false),
      evidence: () => `employee_cross_check=true,all_documents_match=false`
    },
    {
      code: "P_EMPLOYEE_PATIENT_DOC_MISSING",
      points: 6,
      apply_if: () => (employeeCrossCheckRequired === true && emp_patient_document_present === false),
      evidence: () => `employee_cross_check=true,patient_document_present=false`
    },

    // OCR confidence piecewise
    {
      code: "P_OCR_CONF_LOW",
      points_fn: () => {
        if (!Number.isFinite(ocrConfidence)) return 0;
        if (ocrConfidence >= 0.95) return 0;
        if (ocrConfidence >= 0.90) return 4;
        if (ocrConfidence >= 0.80) return 10;
        return 18;
      },
      apply_if: () => Number.isFinite(ocrConfidence),
      evidence: () => `ocr_confidence_avg=${ocrConfidence}`
    },

    { code: "P_PATIENT_NAME_MISSING_OR_SUSPECT", points: 18, apply_if: () => patientNameOk !== true, evidence: () => `patient_name=${patientName || ""}` },
    { code: "P_ISSUER_NAME_MISSING", points: 10, apply_if: () => issuerOkForAuto !== true, evidence: () => `issuer_name=${issuerName || ""}` },
    { code: "P_ATTENDANCE_TYPE_MISSING", points: 6, apply_if: () => attendanceTypeOk !== true, evidence: () => `attendance_type=${attendanceType || ""}` },
    { code: "P_ATTENDANCE_DATE_MISSING", points: 25, apply_if: () => attendanceDateISO === null, evidence: () => `attendance_date=${attendanceDateBR || ""}` },

    {
      code: "P_DOCUMENT_AGE",
      points_fn: () => piecewiseDocAgePenalty(attendanceAgeDays),
      apply_if: () => Number.isFinite(attendanceAgeDays) && attendanceAgeDays > MAX_DOCUMENT_AGE_DAYS_FOR_AUTO,
      evidence: () => `attendance_age_days=${attendanceAgeDays},max_auto_days=${MAX_DOCUMENT_AGE_DAYS_FOR_AUTO},eval_date=${evalISO}`
    },

    {
      code: "P_LEAVE_TEMPORAL_INCONSISTENCY",
      points: PTS_LEAVE_TEMPORAL_INCONSISTENCY,
      apply_if: () => leaveTemporalHighRisk === true,
      evidence: () => `attendance_date=${attendanceDateISO},leave_start_date=${leaveStartISO},diff_days=${leaveTemporalDiffDays}`
    },

    { code: "P_LEAVE_DATES_INCONSISTENT", points: 22, apply_if: () => (leavePresent === true && leaveDatesConsistent === false), evidence: () => `leave_present=true,start=${leaveStartISO},end=${leaveEndISO},indef=${periodoIndefinido || ""}` },

    {
      code: "P_LEAVE_RISK_NOT_LOW",
      points_fn: () => {
        if (!leavePresent) return 0;
        if (leaveDaysRisk === null) return 10;
        const v = String(leaveDaysRisk).toLowerCase();
        if (v === "very_low" || v === "low") return 0;
        if (v === "medium") return 10;
        if (v === "high" || v === "very_high") return 18;
        return 10;
      },
      apply_if: () => leavePresent === true,
      evidence: () => `leave_days_risk=${leaveDaysRisk || ""}`
    },

    // Image penalties (piecewise)
    { code: "P_IMG_COMPLETENESS", points_fn: () => piecewiseCompletenessPenalty(imageScores.completeness), apply_if: () => Number.isFinite(imageScores.completeness), evidence: () => `P_IMG_COMPLETENESS_value=${imageScores.completeness}` },
    { code: "P_IMG_QUALITY", points_fn: () => piecewiseQualityPenalty(imageScores.image_quality), apply_if: () => Number.isFinite(imageScores.image_quality), evidence: () => `P_IMG_QUALITY_value=${imageScores.image_quality}` },
    { code: "P_IMG_CONSISTENCY", points_fn: () => piecewiseConsistencyPenalty(imageScores.consistency), apply_if: () => Number.isFinite(imageScores.consistency), evidence: () => `P_IMG_CONSISTENCY_value=${imageScores.consistency}` },

    // Digital native with physical stamp (preserved)
    { code: "P_DIGITAL_NATIVE_WITH_PHYSICAL_STAMP", points: 70, apply_if: () => digitalNativeWithStampHighRisk === true, evidence: () => `capture_type=${captureType},stamp_valid=${stampValid}` },

    // Capture penalties (preserved)
    { code: "P_CAPTURE_DIGITAL_NATIVE", points: 16, apply_if: () => captureType === "digital_native", evidence: () => `capture_type=${captureType}` },
    { code: "P_CAPTURE_SCAN", points: 8, apply_if: () => captureType === "scan", evidence: () => `capture_type=${captureType}` },
    { code: "P_CAPTURE_OTHER", points: 24, apply_if: () => captureType !== null && !inSet(captureType, ["photo", "scan", "digital_native"]), evidence: () => `capture_type=${captureType}` },

    // Forensic/manipulation penalties (expanded)
    { code: "P_MANIPULATION_ANALYSIS_DETECTED", points: 35, apply_if: () => manipulationDetected === true, evidence: () => "manipulation_analysis.detected=true" },
    { code: "P_DIGITAL_MANIPULATION_INDICATORS", points: 25, apply_if: () => digitalManip !== null && digitalManip !== "none", evidence: () => `digital_manipulation_indicators=${digitalManip}` },
    { code: "P_PHYSICAL_MANIPULATION_INDICATORS", points: 18, apply_if: () => physicalManip !== null && physicalManip !== "none", evidence: () => `physical_manipulation_indicators=${physicalManip}` },
    { code: "P_AI_GENERATION_INDICATORS", points: 30, apply_if: () => aiIndicators !== null && aiIndicators !== "none", evidence: () => `ai_generation_or_reconstruction_indicators=${aiIndicators}` },
    { code: "P_VISUAL_QUALITY_ISSUES", points: 12, apply_if: () => anyVisualIssues === true, evidence: () => `visual_quality_issues=${JSON.stringify(visualIssues)}` },
    { code: "P_SIGNATURE_ILLEGIBLE", points: 8, apply_if: () => (typeof forensicNotes === "string" && forensicNotes.toLowerCase().includes("signature_illegible")), evidence: () => `forensic_notes=${forensicNotes}` },

    // Elements penalties (recalibrated)
    { code: "P_MISSING_MANDATORY_FIELDS", points: 26, apply_if: () => hasMandatoryFields === false, evidence: () => "has_mandatory_fields=false" },
    { code: "P_MISSING_DOCTOR_DATA", points: 10, apply_if: () => hasDoctorData === false, evidence: () => "has_doctor_data=false" },
    { code: "P_MISSING_PATIENT_DATA", points: 14, apply_if: () => hasPatientData === false, evidence: () => "has_patient_data=false" },
    { code: "P_MISSING_DISEASE_DATA", points: 10, apply_if: () => hasDiseaseData === false, evidence: () => "has_disease_data=false" },

    // richer elements, if present as booleans
    { code: "P_MISSING_ISSUER_DATA", points: 14, apply_if: () => hasIssuerData === false, evidence: () => "has_issuer_data=false" },
    { code: "P_MISSING_ATTENDANCE_DATA", points: 10, apply_if: () => hasAttendanceData === false, evidence: () => "has_attendance_data=false" },
    { code: "P_MISSING_LOCALITY_DATA", points: 6, apply_if: () => hasLocalityData === false, evidence: () => "has_locality_data=false" },
    { code: "P_MISSING_DISCLAIMER", points: 2, apply_if: () => hasDisclaimer === false, evidence: () => "has_disclaimer=false" },

    // Patient doc undefined
    { code: "P_PATIENT_DOC_UNDEFINED", points: 4, apply_if: () => String(patientDocValue || "").toLowerCase() === "undefined", evidence: () => "patient_document_value=undefined" },

    // CRM/CFM penalties
    { code: "P_CRM_MISSING", points: 18, apply_if: () => crmPresent !== true, evidence: () => "crm_number_missing" },
    { code: "P_CRM_INACTIVE_OR_INVALID", points: 26, apply_if: () => crmPresent === true && crmStatusNorm === "inactive", evidence: () => `crm_status=${crmStatusNorm}` },
    { code: "P_CRM_NOT_VERIFIED", points: 18, apply_if: () => crmPresent === true && crmVerifiedAndValid !== true && crmStatusNorm !== "inactive", evidence: () => `cfm_match_status=${cfmMatchStatus || ""},match_score=${cfmMatchScore || ""}` },

    // QR penalty (in addition to gate)
    { code: "P_QR_PRESENT_BUT_INVALID", points: 12, apply_if: () => qrPresentButInvalid === true, evidence: () => `qr_exists=${qrExists},qr_decodable=${qrDecodable},qr_url_status=${qrUrlStatus || ""}` },

    // CID penalty
    { code: "P_CID_INVALID", points: 18, apply_if: () => cidValid === false, evidence: () => `cid_parent=${cidParent}` },
    { code: "P_CID_MISSING", points: 8, apply_if: () => cidParent === null, evidence: () => "cid_parent_missing" },

    // preliminary risk penalty (when not gate)
    { code: "P_PRELIM_MEDIUM_RISK", points: 15, apply_if: () => visualRisk === "medium", evidence: () => `visual_risk=${visualRisk}` },

    // min auth (if no gate forced score for any reason)
    { code: "P_MISSING_MIN_AUTH", points: 25, apply_if: () => hasMinAuth === false, evidence: () => `has_strong_stamp_signature_auth=${hasStrongStampSignatureAuth},has_valid_qr_auth=${hasValidQrAuth}` },

    // future attendance penalty (in addition to gate)
    { code: "P_FUTURE_ATTENDANCE_DATE", points: 40, apply_if: () => isFutureAttendance === true, evidence: () => `attendance_date=${attendanceDateISO},eval_date=${evalISO}` }
  ],

  bonuses: [
    // optional: employee strong match bonus
    {
      code: "B_EMPLOYEE_NAME_STRONG_MATCH",
      points: -6,
      apply_if: () => (employeeCrossCheckRequired === true && Number.isFinite(emp_name_score) && emp_name_score >= 0.85),
      evidence: () => `employee_cross_check=true,name_score=${emp_name_score}`
    },

    { code: "B_VALID_QR", points: -25, apply_if: () => hasValidQrAuth === true, evidence: () => "valid_qr_auth=true" },
    { code: "B_CRM_VERIFIED_MATCHED", points: -15, apply_if: () => crmVerifiedAndValid === true, evidence: () => `cfm_match_score=${cfmMatchScore}` },
    { code: "B_CID_VALID", points: -8, apply_if: () => cidValid === true, evidence: () => `cid_parent=${cidParent}` },
    { code: "B_STAMP_SIGNATURE_VALID", points: -8, apply_if: () => hasStrongStampSignatureAuth === true, evidence: () => "stamp_valid=true & signature_valid=true" }
  ],

  acceptance_penalties: [
    { a: "A1_is_medical_certificate", code: "P_A1_FAIL", points: 10, apply_if: () => isMedicalCertificate !== true },
    { a: "A2_capture_type_recognized", code: "P_A2_FAIL", points: 3, apply_if: () => captureOkForAuto !== true },
    { a: "A3_ocr_confidence_gte_0_95", code: "P_A3_FAIL", points: 2, apply_if: () => ocrOkForAuto !== true },
    { a: "A4_patient_name_present_no_question_marks", code: "P_A4_FAIL", points: 4, apply_if: () => patientNameOk !== true },
    { a: "A5_doctor_name_crm_present_and_cfm_valid", code: "P_A5_FAIL", points: 4, apply_if: () => !(doctorFieldsOkForAuto === true && crmVerifiedAndValid === true) },
    { a: "A6_issuer_name_present", code: "P_A6_FAIL", points: 2, apply_if: () => issuerOkForAuto !== true },
    { a: "A7_attendance_type_identified", code: "P_A7_FAIL", points: 2, apply_if: () => attendanceTypeOk !== true },
    { a: "A8_attendance_date_present_within_max_days", code: "P_A8_FAIL", points: 4, apply_if: () => attendanceDataOkForAuto !== true },
    { a: "A9_leave_absent_or_low_risk_and_consistent", code: "P_A9_FAIL", points: 3, apply_if: () => leaveOkForAuto !== true },
    { a: "A10_cid_present_and_found_true", code: "P_A10_FAIL", points: 3, apply_if: () => cidOkForAuto !== true },
    { a: "A11_elements_mandatory_stamp_or_qr_and_entities", code: "P_A11_FAIL", points: 6, apply_if: () => elementsOkForAuto !== true },
    { a: "A12_no_manipulation_no_visual_quality_issues", code: "P_A12_FAIL", points: 6, apply_if: () => noManipulationOkForAuto !== true },
    { a: "A13_qr_when_present_must_be_valid", code: "P_A13_FAIL", points: 4, apply_if: () => (qrPresentButInvalid === true) },
    { a: "A14_image_scores_all_gte_0_9", code: "P_A14_FAIL", points: 3, apply_if: () => imageScoresOkForAuto !== true },
    { a: "A15_preliminary_low_and_accept", code: "P_A15_FAIL", points: 2, apply_if: () => prelimOkForAuto !== true },

    // employee acceptance (only when employe_data exists)
    { a: "A16_employee_name_match_if_present", code: "P_A16_FAIL", points: 8, apply_if: () => (employeeCrossCheckRequired === true && employeeNameOk !== true) }
  ],

  bonus_cap: BONUS_CAP
};

// =========================================================
// ACCEPTANCE CHECKLIST (whitelist)
// =========================================================
const acceptanceChecklist = [
  { code: "A1_is_medical_certificate", ok: isMedicalCertificate === true },
  { code: "A2_capture_type_recognized", ok: captureOkForAuto === true },
  { code: "A3_ocr_confidence_gte_0_90", ok: ocrOkForAuto === true },
  { code: "A4_patient_name_present_no_question_marks", ok: patientNameOk === true },
  { code: "A5_doctor_name_crm_present_and_cfm_valid", ok: (doctorFieldsOkForAuto === true && crmVerifiedAndValid === true) },
  { code: "A6_issuer_name_present", ok: issuerOkForAuto === true },
  { code: "A7_attendance_type_identified", ok: attendanceTypeOk === true },
  { code: "A8_attendance_date_present_within_max_days", ok: attendanceDataOkForAuto === true },
  { code: "A9_leave_absent_or_low_risk_and_consistent", ok: leaveOkForAuto === true },
  { code: "A10_cid_present_and_found_true", ok: cidOkForAuto === true },
  { code: "A11_elements_mandatory_stamp_or_qr_and_entities", ok: elementsOkForAuto === true },
  { code: "A12_no_manipulation_no_visual_quality_issues", ok: noManipulationOkForAuto === true },
  { code: "A13_qr_when_present_must_be_valid", ok: (qrPresentButInvalid === false) },
  { code: "A14_image_scores_all_gte_0_9", ok: imageScoresOkForAuto === true },
  { code: "A15_preliminary_low_and_accept", ok: prelimOkForAuto === true },

  // employee: only meaningful when employee data exists
  { code: "A16_employee_name_match_if_present", ok: (employeeCrossCheckRequired ? (employeeNameOk === true) : true) }
];

const isAutoApprovedEligible = acceptanceChecklist.every(x => x.ok === true);

// =========================================================
// RULE ENGINE EXECUTION
// =========================================================
const gates_failed = [];
const penalties_applied = [];
const bonuses_applied = [];

let forcedDecision = null;
let forcedScore = null;
let forcedRationale = null;

// ---- Gates first (authority) ----
for (const g of RULES.gates) {
  let fail = false;
  try { fail = !!g.fail_if(); } catch { fail = false; }

  if (fail) {
    gates_failed.push({ code: g.code, name: g.name, severity: g.severity || "unknown" });

    // Gate penalty always recorded (and scored)
    if (g.penalty && Number.isFinite(g.penalty.points) && g.penalty.points > 0) {
      addPenalty(penalties_applied, g.penalty.code, g.penalty.points, `gate=${g.code}`, { source: "gate" });
    }

    // Some gates force decision/score; some only annotate.
    const force = (g.force === false) ? false : true;
    if (force && forcedDecision === null) {
      forcedDecision = g.decision;
      forcedScore = g.base_score;
      forcedRationale = (typeof g.rationale === "function") ? g.rationale() : null;
    }
  }
}

// ---- Compute penalties (major signals) ----
let computedScore = BASE_RISK_SCORE;

for (const p of RULES.penalties) {
  let apply = false;
  try { apply = !!p.apply_if(); } catch { apply = false; }
  if (!apply) continue;

  const pts = (typeof p.points_fn === "function") ? p.points_fn() : p.points;
  const points = Number(pts);
  if (!Number.isFinite(points) || points <= 0) continue;

  const ev = (typeof p.evidence === "function") ? p.evidence() : (p.evidence || "");
  addPenalty(penalties_applied, p.code, points, ev, { source: "signal" });
  computedScore += points;
}

// ---- Acceptance-failure penalties (small deltas) ----
for (const ap of RULES.acceptance_penalties) {
  let apply = false;
  try { apply = !!ap.apply_if(); } catch { apply = false; }
  if (!apply) continue;

  addPenalty(penalties_applied, ap.code, ap.points, `acceptance_fail=${ap.a}`, { source: "acceptance" });
  computedScore += ap.points;
}

// ---- Bonuses (cap to -40 total) ----
let bonusTotal = 0;
for (const b of RULES.bonuses) {
  let apply = false;
  try { apply = !!b.apply_if(); } catch { apply = false; }

  // 🚫 NEVER apply bonuses if minimum structural integrity is broken
  if (apply && hasMinimumStructuralIntegrity === true) {
    addBonus(bonuses_applied, b.code, b.points, (typeof b.evidence === "function") ? b.evidence() : (b.evidence || ""), { source: "bonus" });
    bonusTotal += b.points;
  }
}

if (bonusTotal < RULES.bonus_cap) {
  // clamp bonus total to -40 by scaling
  const scale = RULES.bonus_cap / bonusTotal; // both negative => positive <=1
  let adjustedTotal = 0;
  const adjusted = [];

  for (const b of bonuses_applied) {
    const newPoints = Math.trunc(b.points * scale);
    adjusted.push({ ...b, points: newPoints, evidence: `${b.evidence}|scaled=${scale}` });
    adjustedTotal += newPoints;
  }

  bonuses_applied.length = 0;
  bonuses_applied.push(...adjusted);
  bonusTotal = adjustedTotal;
}

computedScore += bonusTotal;

// Convergence floors (preserved)
if (visualRisk === "medium" && computedScore < 40) computedScore = 40;
if (visualRisk === "high" && computedScore < 60) computedScore = 60;

computedScore = clampScore(computedScore);

// If gate forced a minimum score, keep it as a floor (not a replacement)
let score = (forcedScore !== null) ? Math.max(Number(forcedScore), computedScore) : computedScore;
score = clampScore(score);

// =========================================================
// RISK LEVEL + DECISION LOGIC (aligned to 0-25 / 26-50 / 51+)
// =========================================================
function riskLevelFromScore(s) {
  if (s <= 25) return "LOW";
  if (s <= 50) return "MEDIUM";
  return "HIGH";
}

let riskLevel = riskLevelFromScore(score);

// Decision default by score
let decisionStatus =
  riskLevel === "LOW" ? "approved_low_risk" :
  riskLevel === "MEDIUM" ? "approved_with_reservations" :
  "manual_verification_required";

let manualReviewRequired =
  decisionStatus === "manual_verification_required" ||
  decisionStatus === "rejected_high_risk" ||
  riskLevel === "HIGH";

// If forced decision (hard gate), override decision (score already floored)
if (forcedDecision !== null) {
  decisionStatus = forcedDecision;
  riskLevel = "HIGH";
  manualReviewRequired = true;
}

// =========================================================
// NON-NEGOTIABLE ACCEPTANCE WHITELIST ENFORCEMENT (preserved)
// =========================================================
const cfmNotValidated = !crmVerifiedAndValid;

if (decisionStatus === "approved_low_risk") {
  if (!isAutoApprovedEligible) {
    decisionStatus = "manual_verification_required";
    manualReviewRequired = true;
    // ensure score at least MEDIUM when whitelist fails
    if (score < 26) score = 26;
    riskLevel = riskLevelFromScore(score);
  }
}

// Even if score is low, if CFM not validated, force manual review
if (cfmNotValidated) {
  if (decisionStatus !== "rejected_high_risk") {
    decisionStatus = "manual_verification_required";
    manualReviewRequired = true;
    if (score < 26) score = 26;
    riskLevel = riskLevelFromScore(score);
  }
}

// If not a recognized medical certificate -> reject
if (isMedicalCertificate !== true) {
  decisionStatus = "rejected_high_risk";
  manualReviewRequired = true;
  score = Math.max(score, 85);
  riskLevel = "HIGH";
}

// If preliminary says reject/high but gate did not fire (shouldn't happen), enforce safety
if ((recommendedAction === "reject" || visualRisk === "high") && decisionStatus !== "rejected_high_risk") {
  decisionStatus = "rejected_high_risk";
  manualReviewRequired = true;
  score = Math.max(score, 95);
  riskLevel = "HIGH";
}

// =========================================================
// FORENSIC SUMMARY (strict, no guessing)
// =========================================================
const forensic_summary = {
  visual_manipulation_detected: (manipulationDetected === true) || (digitalManip !== null && digitalManip !== "none"),
  ai_generation_suspected: (aiIndicators !== null && aiIndicators !== "none"),
  visual_quality_resume: anyVisualIssues ? "visual_issues_detected" : "no_visual_issues_detected"
};

// =========================================================
// ELEMENTS CHECKS (compat)
// =========================================================
const elements_checks = {
  has_valid_qr_auth: hasValidQrAuth,
  has_strong_stamp_signature_auth: hasStrongStampSignatureAuth,
  has_min_auth: hasMinAuth,
  crm_status_normalized: crmStatusNorm,
  attendance_date_parsed: attendanceDateISO,
  is_future_date: isFutureAttendance
};

// =========================================================
// RATIONALE (score-aware) + FULL MAP + TRAVA
// =========================================================
const rationaleCandidates = [];

if (forcedRationale && forcedRationale.length) {
  for (const r of forcedRationale) rationaleCandidates.push({ impact: 999, text: r, kind: "negative" });
} else {
  for (const p of penalties_applied) rationaleCandidates.push({ impact: Math.abs(p.points), text: p.code, kind: "negative" });
  for (const b of bonuses_applied) rationaleCandidates.push({ impact: Math.abs(b.points), text: b.code, kind: "positive" });

  if (!isAutoApprovedEligible) rationaleCandidates.push({ impact: 500, text: "Auto-approval prerequisites not fully satisfied", kind: "negative" });
  if (cfmNotValidated) rationaleCandidates.push({ impact: 450, text: "Doctor CFM validation missing or not confirmed", kind: "negative" });

  if (employeeCrossCheckRequired) {
    if (employeeNameOk) rationaleCandidates.push({ impact: 120, text: "R_OK_EMPLOYEE_NAME_MATCH", kind: "positive" });
    if (emp_all_documents_match === true) rationaleCandidates.push({ impact: 110, text: "R_OK_EMPLOYEE_DOCS_MATCH", kind: "positive" });
  }

  // Score <= 25: include explicit "approval drivers" (positive-only)
  if (score <= 25) {
    rationaleCandidates.push({ impact: 140, text: "R_OK_DOCUMENT_CONSISTENT", kind: "positive" });
    if (hasMinAuth) rationaleCandidates.push({ impact: 130, text: "R_OK_AUTH_PRESENT", kind: "positive" });
    if (crmVerifiedAndValid) rationaleCandidates.push({ impact: 125, text: "R_OK_DOCTOR_VERIFIED", kind: "positive" });
    if (cidOkForAuto) rationaleCandidates.push({ impact: 115, text: "R_OK_CID_VALID", kind: "positive" });
    if (noManipulationOkForAuto) rationaleCandidates.push({ impact: 120, text: "R_OK_NO_MANIPULATION", kind: "positive" });
    if (ocrOkForAuto) rationaleCandidates.push({ impact: 90, text: "R_OK_OCR_HIGH_CONF", kind: "positive" });
    if (attendanceDataOkForAuto) rationaleCandidates.push({ impact: 85, text: "R_OK_ATTENDANCE_WITHIN_WINDOW", kind: "positive" });
  }
}

rationaleCandidates.sort((a, b) => b.impact - a.impact);

