// ---- rationaleText with TRAVA: never expose raw codes ----
function rationaleText(codeOrText) {
  const m = getRationaleDictionary();
  if (m[codeOrText]) return m[codeOrText];

  const s = String(codeOrText || "").trim();

  // Hard trap: never expose raw rule codes to clients
  if (/^(P_|B_|G_|A_)/.test(s)) {
    const pretty = s
      .replace(/^(P_|B_|G_|A_)/, "")
      .replace(/^A\d+_/, "")
      .replace(/_/g, " ")
      .toLowerCase();
    return pretty.charAt(0).toUpperCase() + pretty.slice(1);
  }

  return s || "Manual verification required";
}

// score-aware selection rules
let allowKinds;
if (score <= 25) {
  allowKinds = new Set(["positive"]);
} else if (score <= 50) {
  allowKinds = new Set(["negative"]);
} else {
  allowKinds = new Set(["negative"]);
}

const finalRationale = [];
for (const c of rationaleCandidates) {
  if (c.kind && !allowKinds.has(c.kind)) continue;
  if (score <= 25 && String(c.text || "").startsWith("P_")) continue;

  const t = rationaleText(c.text);
  if (!t) continue;

  if (!finalRationale.includes(t)) finalRationale.push(t);
  if (finalRationale.length >= MAX_RATIONALE_ITENS) break;
}

if (finalRationale.length === 0) {
  finalRationale.push(score <= 25 ? "Approved (low risk)" : "Manual verification required");
}

