    };
  }

  // ---- FULL RATIONALE MAP (dictionary + completeness report) ----
  if (ENABLE_RULE_ENGINE_DEBUG_RATIONALE_MAP) {
    const dict = getRationaleDictionary();

    const allCodes = [];
    allCodes.push("Auto-approval prerequisites not fully satisfied");
    allCodes.push("Doctor CFM validation missing or not confirmed");

    for (const g of RULES.gates) {
      if (g.penalty && g.penalty.code) allCodes.push(g.penalty.code);
    }
    for (const p of RULES.penalties) allCodes.push(p.code);
    for (const b of RULES.bonuses) allCodes.push(b.code);
    for (const ap of RULES.acceptance_penalties) allCodes.push(ap.code);

    allCodes.push(
      "R_OK_DOCUMENT_CONSISTENT",
      "R_OK_AUTH_PRESENT",
      "R_OK_DOCTOR_VERIFIED",
      "R_OK_CID_VALID",
      "R_OK_NO_MANIPULATION",
      "R_OK_OCR_HIGH_CONF",
      "R_OK_ATTENDANCE_WITHIN_WINDOW",
      "R_OK_EMPLOYEE_NAME_MATCH",
      "R_OK_EMPLOYEE_DOCS_MATCH"
    );

    const uniq = Array.from(new Set(allCodes));
    const unmapped = uniq.filter(code => !(code in dict));

    debugObj.rationale_map = {
      dictionary: dict,
      expected_codes: uniq,
      unmapped_codes: unmapped
    };
  }

  out._rule_engine_debug = debugObj;
}

return [{ json: out }];

/**
 * MIA-SADM — Patient vs Employee Comparator (v1.2.1)
 * n8n Code Node (JavaScript)
 *
 * CORREÇÃO SOLICITADA:
 * - O NOME do employee é o único “switch”:
 *   - Se employee_name estiver vazio -> retorna [] (nada)
 *   - Se employee_name existir -> mantém todo o resto exatamente como está
 *
 * AJUSTE (mínimo):
 * - Inclui os parâmetros de entrada do employee no output.
 */

// ---------------------- Helpers ----------------------

function str(v) {
  return (v ?? "").toString().trim();
}
function upper(v) {
  return str(v).toUpperCase();
}
function digitsOnly(v) {
  const d = str(v).replace(/\D+/g, "");
  return d.length ? d : "";
}
function hasAny(obj, keys) {
  if (!obj || typeof obj !== "object") return false;
  return keys.some(k => obj[k] !== undefined && obj[k] !== null && str(obj[k]) !== "");
}

function normalizeName(name) {
  return (name || "")
    .toUpperCase()
    .replace(/\b(DR|DRA|DR\.)\b/g, "")
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z\s]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}
function tokenize(name) {
  const n = normalizeName(name);
  return n ? n.split(" ").filter(Boolean) : [];
}
function levenshtein(a, b) {
  a = a || ""; b = b || "";
  const n = a.length, m = b.length;
  if (n === 0) return m;
  if (m === 0) return n;

  const dp = new Array(m + 1);
  for (let j = 0; j <= m; j++) dp[j] = j;

  for (let i = 1; i <= n; i++) {
    let prev = dp[0];
    dp[0] = i;
    for (let j = 1; j <= m; j++) {
      const tmp = dp[j];
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[j] = Math.min(dp[j] + 1, dp[j - 1] + 1, prev + cost);
      prev = tmp;
    }
  }
  return dp[m];
}

/**
 * Score ∈ [0,1]
 */
function nameSimilarity(a, b) {
  const na = normalizeName(a);
  const nb = normalizeName(b);
  if (!na || !nb) return 0;
  if (na === nb) return 1;

  const ta = tokenize(na);
  const tb = tokenize(nb);
  if (!ta.length || !tb.length) return 0;

  const setA = new Set(ta);
  const setB = new Set(tb);
  const inter = [...setA].filter(t => setB.has(t)).length;

  const prec = inter / setA.size;
  const rec = inter / setB.size;
  const f1 = (prec + rec) > 0 ? (2 * prec * rec) / (prec + rec) : 0;

  const surnameA = ta[ta.length - 1];
  const surnameB = tb[tb.length - 1];

  let score = 0.75 * f1;

  if (surnameA === surnameB) {
    score += 0.25;
  } else {
    const dist = levenshtein(surnameA, surnameB);
    const maxLen = Math.max(surnameA.length, surnameB.length, 1);
    const sim = 1 - (dist / maxLen);

    if (sim >= 0.7) score *= 0.55;
    else if (sim >= 0.5) score *= 0.75;
  }

  return Math.max(0, Math.min(score, 1));
}

// ---------------------- Inputs (EXPLÍCITOS) ----------------------

// Patient -> preferir sempre o node "Output Analise Imagem"
const patientNode = $("Output Analise Imagem").first()?.json ?? {};
const patient = patientNode.patient_identification
  ?? ($input.first()?.json?.patient_identification)
  ?? {};

const patient_name = str(patient.patient_name);
const patient_document_type = upper(patient.patient_document_type); // "CPF" | "RG" | ""
const patient_document_digits = digitsOnly(patient.patient_document_value);

// Employee -> preferir sempre o node "Edit Fields"
let employee = $("Edit Fields").first()?.json;

// fallback só se o $input realmente tiver campos de employee
if (!employee || !hasAny(employee, ["employee_name", "employee_identity_document", "employee_national_document"])) {
  const inJson = $input.first()?.json ?? {};
  if (hasAny(inJson, ["employee_name", "employee_identity_document", "employee_national_document"])) {
    employee = inJson;
  } else {
    const wb = $("Webhook").first()?.json?.body ?? {};
    if (hasAny(wb, ["employee_name", "employee_identity_document", "employee_national_document"])) {
      employee = wb;
    } else {
      employee = {};
    }
  }
}

const employee_name = str(employee.employee_name);
const employee_national_digits = digitsOnly(employee.employee_national_document); // CPF employee
const employee_identity_digits = digitsOnly(employee.employee_identity_document); // RG employee

// ---------------------- SWITCH: employee_name ----------------------

if (!employee_name) {
  return {};
}

// ---------------------- Presence flags (mantido) ----------------------

const patient_data_present = !!(patient_name || patient_document_digits);
const employee_data_present = !!(employee_name || employee_national_digits || employee_identity_digits);

// ---------------------- Name comparison ----------------------

let patient_employee_name_score = null;
let patient_employee_name_match = null;

const NAME_MATCH_THRESHOLD = 0.85;

if (patient_name && employee_name) {
  patient_employee_name_score = Number(nameSimilarity(patient_name, employee_name).toFixed(3));
  patient_employee_name_match = patient_employee_name_score >= NAME_MATCH_THRESHOLD;
}

// ---------------------- Document comparisons (mantido) ----------------------

let patient_employee_national_document_match = null; // boolean | null
if (employee_national_digits) {
  if (patient_document_type === "CPF" && patient_document_digits) {
    patient_employee_national_document_match = (patient_document_digits === employee_national_digits);
  } else {
    patient_employee_national_document_match = null;
  }
}

let patient_employee_identity_document_match = null; // boolean | null
if (employee_identity_digits) {
  if (patient_document_type === "RG" && patient_document_digits) {
    patient_employee_identity_document_match = (patient_document_digits === employee_identity_digits);
  } else {
    patient_employee_identity_document_match = null;
  }
}

const required = [];
if (employee_national_digits) required.push(patient_employee_national_document_match);
if (employee_identity_digits) required.push(patient_employee_identity_document_match);

let all_documents_match = null;
if (required.length > 0) {
  if (required.some(v => v === null)) all_documents_match = null;
  else all_documents_match = required.every(v => v === true);
}

// ---------------------- Output (mantido + employee_input) ----------------------

return [{
  json: {
    patient_data_present,
    employee_data_present,

    // NEW (mínimo): parâmetros de entrada do employee
    employee_input: {
      employee_name: employee_name,
      employee_national_document: str(employee.employee_national_document),
      employee_identity_document: str(employee.employee_identity_document)
    },

    patient_employee_name_score,
    patient_employee_name_match,

    patient_document_type: patient_document_type || "",
    patient_document_present: !!patient_document_digits,

    patient_employee_national_document_match,
    patient_employee_identity_document_match,

    all_documents_match,

    _presence: {
      patient: { name: !!patient_name, document: !!patient_document_digits },
      employee: { name: !!employee_name, national_document: !!employee_national_digits, identity_document: !!employee_identity_digits }
    }
  }
}];
